318→    also {
319→        println("Processing ${text.replaceTabAndNewline()} : Type $elementType with parent ${treeParent?.elementType} ")
320→        children()
321→            .toList()
322→            .map {
323→                println("  ${it.text.replaceTabAndNewline()} : Type ${it.elementType}")
324→            }
325→    }
