327→private fun String.replaceTabAndNewline(): String = replace("\t", "\\t").replace("\n", "\\n")
328→
329→/**
330→ * Verifies that a leaf containing a newline exist in the closed range [from] - [to]. Also, returns true in case any of
331→ * the boundary nodes [from] or [to] contains a newline.
332→ */
333→public fun hasNewLineInClosedRange(
334→    from: ASTNode,
335→    to: ASTNode,
336→): Boolean =
337→    from.isWhiteSpaceWithNewline() ||
338→        leavesInOpenRange(from, to).any { it.textContains('\n') } ||
339→        to.isWhiteSpaceWithNewline()
340→
341→/**
342→ * Verifies that no leaf contains a newline in the closed range [from] - [to]. Also, the boundary nodes [from] and [to]
343→ * should not contain a newline.
344→ */
345→public fun noNewLineInClosedRange(
346→    from: ASTNode,
347→    to: ASTNode,
348→): Boolean =
349→    !from.isWhiteSpaceWithNewline() &&
350→        noNewLineInOpenRange(from, to) &&
351→        !to.isWhiteSpaceWithNewline()
352→
353→/**
354→ * Verifies that no leaf contains a newline in the open range [from] - [to]. This means that the boundary nodes are excluded from the range
355→ * in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first leaf node in the sequence is the first
356→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node prior
357→ * to this [CompositeElement].
358→ */
359→public fun noNewLineInOpenRange(
360→    from: ASTNode,
361→    to: ASTNode,
362→): Boolean = leavesInOpenRange(from, to).none { it.textContains('\n') }
363→
364→/**
365→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
366→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
367→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
368→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
369→ */
370→public fun leavesInOpenRange(
371→    from: ASTNode,
372→    to: ASTNode,
373→): Sequence<ASTNode> =
374→    from
375→        .leaves()
376→        .takeWhile { it != to && it != to.firstChildNode }
377→
378→public fun ASTNode.isValOrVarKeyword(): Boolean = elementType == VAL_KEYWORD || elementType == VAR_KEYWORD || elementType == VARARG_KEYWORD
379→
380→/**
381→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
382→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
383→ */
384→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
385→    val sequence =
386→        if (isLeaf()) {
387→            sequenceOf(this)
388→        } else {
389→            emptySequence()
390→        }
391→    return sequence.plus(leaves(forward))
392→}
393→
394→/**
395→ * Get all leaves on the same line as the given node including the whitespace indentation. Note that the whitespace indentation may start
396→ * with zero or more newline characters.
397→ */
398→public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
399→    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
400→    return getFirstLeafOnLineOrSelf()
401→        .leavesIncludingSelf()
402→        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
403→}
404→
405→internal fun ASTNode.getFirstLeafOnLineOrSelf() = prevLeaf { it.textContains('\n') || it.prevLeaf() == null }!!
406→
407→internal fun ASTNode.getLastLeafOnLineOrNull() = nextLeaf { it.textContains('\n') }?.prevLeaf()
408→
409→/**
410→ * Get the total length of all leaves on the same line as the given node including the whitespace indentation but excluding all leading
411→ * newline characters in the whitespace indentation.
412→ */
413→public fun ASTNode.lineLengthWithoutNewlinePrefix(): Int =
414→    leavesOnLine()
415→        .joinToString(separator = "") { it.text }
416→        // If a line is preceded by a blank line then the ident contains multiple newline chars
417→        .dropWhile { it == '\n' }
418→        // In case the last element on the line would contain a newline then only include chars before that newline. Note that this should
419→        // not occur if the AST is parsed correctly
420→        .takeWhile { it != '\n' }
421→        .length
